    97â†’        </span>
    98â†’        <button
    99â†’          onClick={handleDelete}
   100â†’          className="rounded-md px-2.5 py-1 text-[12px] font-medium text-[#991b1b] transition-colors hover:bg-[#fef2f2]"
   101â†’          style={{ fontFamily: "var(--font-dm-sans)" }}
