   197â†’                    style={{ fontFamily: "var(--font-dm-sans)" }}
   198â†’                  >
   199â†’                    Provider
   200â†’                  </th>
   201â†’                  <th
   202â†’                    className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   203â†’                    style={{ fontFamily: "var(--font-dm-sans)" }}
   204â†’                  >
   205â†’                    Repository
   206â†’                  </th>
   207â†’                  <th
   208â†’                    className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
