     7â†’import {
     8â†’  semanticReleases as srApi,
     9â†’  projects as projectsApi,
    10â†’} from "@/lib/api/client";
    11â†’import { VersionChip } from "@/components/ui/version-chip";
    12â†’import { ConfirmDialog } from "@/components/ui/confirm-dialog";
    13â†’import { Trash2 } from "lucide-react";
    14â†’import { timeAgo } from "@/lib/format";
    15â†’import type { Project, SemanticRelease } from "@/lib/api/types";
    16â†’
    17â†’/* ---------- Urgency chip ---------- */
    18â†’
    19â†’const URGENCY_COLORS: Record<string, { bg: string; text: string }> = {
    20â†’  critical: { bg: "#dc2626", text: "#ffffff" },
    21â†’  high: { bg: "#f97316", text: "#ffffff" },
    22â†’};
    23â†’
    24â†’function UrgencyChip({ urgency }: { urgency: string }) {
    25â†’  const u = urgency.toLowerCase();
    26â†’  const style = URGENCY_COLORS[u];
    27â†’  if (!style) return null;
    28â†’  return (
    29â†’    <span
    30â†’      className="inline-flex items-center rounded-full px-2 py-0.5 text-[11px] font-medium leading-none"
    31â†’      style={{ backgroundColor: style.bg, color: style.text }}
    32â†’    >
    33â†’      {urgency}
    34â†’    </span>
    35â†’  );
    36â†’}
    37â†’
    38â†’/* ---------- Helpers ---------- */
    39â†’
    40â†’function truncate(str: string, max: number): string {
    41â†’  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    42â†’}
    43â†’
    44â†’const PER_PAGE = 15;
    45â†’
    46â†’/* ---------- Main component ---------- */
    47â†’
    48â†’export function SemanticReleasesList() {
    49â†’  return (
    50â†’    <Suspense>
    51â†’      <SemanticReleasesListInner />
    52â†’    </Suspense>
    53â†’  );
    54â†’}
    55â†’
    56â†’function SemanticReleasesListInner() {
    57â†’  const searchParams = useSearchParams();
    58â†’  const initialProject = searchParams.get("project") ?? "all";
    59â†’  const [page, setPage] = useState(1);
    60â†’  const [projectFilter, setProjectFilter] = useState<string>(initialProject);
    61â†’  const [deletingId, setDeletingId] = useState<string | null>(null);
    62â†’
    63â†’  /* Fetch projects for the filter dropdown */
    64â†’  const { data: projectsData } = useSWR("projects-for-sr-filter", () =>
    65â†’    projectsApi.list()
    66â†’  );
    67â†’  const projectsById = new Map<string, Project>();
    68â†’  for (const p of projectsData?.data ?? []) projectsById.set(p.id, p);
    69â†’
    70â†’  /* Fetch semantic releases â€” scoped by project or all */
    71â†’  const { data: scopedData, isLoading: scopedLoading, mutate: mutateScopedData } = useSWR(
    72â†’    projectFilter !== "all" ? ["sr-scoped", page, projectFilter] : null,
    73â†’    () => srApi.list(projectFilter, page, PER_PAGE)
    74â†’  );
    75â†’
    76â†’  const { data: allData, isLoading: allLoading, mutate: mutateAllData } = useSWR(
    77â†’    projectFilter === "all" ? ["sr-all", page] : null,
    78â†’    () => srApi.listAll(page, PER_PAGE)
    79â†’  );
    80â†’
    81â†’  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;
    82â†’  const releases: SemanticRelease[] =
    83â†’    projectFilter !== "all"
    84â†’      ? scopedData?.data ?? []
    85â†’      : allData?.data ?? [];
    86â†’
    87â†’  const mutateData = projectFilter !== "all" ? mutateScopedData : mutateAllData;
    88â†’
    89â†’  /* Pagination math */
    90â†’  const activeData = projectFilter !== "all" ? scopedData : allData;
    91â†’  const total = activeData?.meta?.total ?? 0;
    92â†’  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
    93â†’  const startRow = (page - 1) * PER_PAGE + 1;
    94â†’  const endRow = Math.min(page * PER_PAGE, total);
    95â†’
    96â†’  return (
    97â†’    <div className="space-y-6 fade-in">
    98â†’      {/* Page title */}
    99â†’      <h1
   100â†’        style={{
   101â†’          fontFamily: "var(--font-fraunces)",
   102â†’          fontSize: "24px",
   103â†’          fontWeight: 700,
   104â†’          color: "#111113",
   105â†’        }}
   106â†’      >
   107â†’        Semantic Releases
   108â†’      </h1>
   109â†’
   110â†’      {/* Project filter */}
   111â†’      <div>
   112â†’        <select
   113â†’          value={projectFilter}
   114â†’          onChange={(e) => {
   115â†’            setProjectFilter(e.target.value);
   116â†’            setPage(1);
   117â†’          }}
   118â†’          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
   119â†’          style={{
   120â†’            fontFamily: "var(--font-dm-sans)",
   121â†’            fontSize: "13px",
   122â†’            color: "#111113",
   123â†’            border: "1px solid #e8e8e5",
   124â†’          }}
   125â†’          onFocus={(e) =>
   126â†’            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
   127â†’          }
   128â†’          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
   129â†’        >
   130â†’          <option value="all">All Projects</option>
   131â†’          {projectsData?.data.map((p: Project) => (
   132â†’            <option key={p.id} value={p.id}>
   133â†’              {p.name}
   134â†’            </option>
   135â†’          ))}
   136â†’        </select>
   137â†’      </div>
   138â†’
   139â†’      {/* Table card */}
   140â†’      <div
   141â†’        className="overflow-hidden rounded-lg bg-white"
   142â†’        style={{ border: "1px solid #e8e8e5" }}
   143â†’      >
   144â†’        {isLoading ? (
   145â†’          <div
   146â†’            className="py-16 text-center"
   147â†’            style={{
   148â†’              fontFamily: "var(--font-dm-sans)",
   149â†’              fontSize: "13px",
   150â†’              color: "#6b7280",
   151â†’            }}
   152â†’          >
   153â†’            Loading...
   154â†’          </div>
   155â†’        ) : releases.length === 0 ? (
   156â†’          <div className="py-16 text-center">
   157â†’            <p
   158â†’              style={{
   159â†’                fontFamily: "var(--font-fraunces)",
   160â†’                fontStyle: "italic",
   161â†’                fontSize: "15px",
   162â†’                color: "#9ca3af",
   163â†’              }}
   164â†’            >
   165â†’              No semantic releases yet
   166â†’            </p>
   167â†’          </div>
   168â†’        ) : (
   169â†’          <table className="w-full">
   170â†’            <thead>
   171â†’              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
   172â†’                {["Project", "Version", "Status", "Urgency", "Age", ""].map(
   173â†’                  (col) => (
   174â†’                    <th
   175â†’                      key={col}
   176â†’                      className="px-4 py-3 text-left"
   177â†’                      style={{
   178â†’                        fontFamily: "var(--font-dm-sans)",
   179â†’                        fontSize: "11px",
   180â†’                        fontWeight: 600,
   181â†’                        textTransform: "uppercase" as const,
   182â†’                        letterSpacing: "0.08em",
   183â†’                        color: "#9ca3af",
   184â†’                      }}
   185â†’                    >
   186â†’                      {col}
   187â†’                    </th>
   188â†’                  )
   189â†’                )}
   190â†’              </tr>
   191â†’            </thead>
   192â†’            <tbody>
   193â†’              {releases.map((sr) => {
   194â†’                const project = projectsById.get(sr.project_id);
   195â†’                return (
   196â†’                  <tr
   197â†’                    key={sr.id}
