   213â†’                        >
   214â†’                          {project.name}
   215â†’                        </Link>
   216â†’                      ) : (
   217â†’                        <span
   218â†’                          style={{
   219â†’                            fontFamily: "var(--font-dm-sans)",
   220â†’                            fontSize: "13px",
