     1â†’export function timeAgo(dateStr?: string | null): string {
     2â†’  if (!dateStr) return "\u2014";
     3â†’  const diff = Date.now() - new Date(dateStr).getTime();
     4â†’  const mins = Math.floor(diff / 60000);
     5â†’  if (mins < 60) return `${mins}m ago`;
     6â†’  const hrs = Math.floor(mins / 60);
     7â†’  if (hrs < 24) return `${hrs}h ago`;
     8â†’  return `${Math.floor(hrs / 24)}d ago`;
     9â†’}
    10â†’
    11â†’export function validateRepository(provider: string, repo: string): string | null {
    12â†’  const trimmed = repo.trim();
    13â†’  if (!trimmed) return null;
    14â†’  if (provider === "github" && /^(https?:\/\/)?github\.com\//i.test(trimmed)) {
    15â†’    return "Use owner/repo format (e.g. ethereum/go-ethereum), not a full URL";
    16â†’  }
    17â†’  if (provider === "dockerhub" && /^(https?:\/\/)?hub\.docker\.com\//i.test(trimmed)) {
    18â†’    return "Use owner/image format (e.g. library/nginx), not a full URL";
    19â†’  }
    20â†’  if (/^https?:\/\//.test(trimmed)) {
    21â†’    return "Use owner/repo format, not a full URL";
    22â†’  }
    23â†’  return null;
    24â†’}
    25â†’
    26â†’export function formatInterval(seconds: number): string {
    27â†’  if (seconds < 60) return `${seconds}s`;
    28â†’  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
    29â†’  if (seconds < 86400) return `${(seconds / 3600).toFixed(1)}h`;
    30â†’  return `${(seconds / 86400).toFixed(1)}d`;
    31â†’}
