    10â†’// SemanticReleasesStore defines the persistence operations for semantic releases.
    11â†’type SemanticReleasesStore interface {
    12â†’	ListAllSemanticReleases(ctx context.Context, page, perPage int) ([]models.SemanticRelease, int, error)
    13â†’	ListSemanticReleases(ctx context.Context, projectID string, page, perPage int) ([]models.SemanticRelease, int, error)
    14â†’	GetSemanticRelease(ctx context.Context, id string) (*models.SemanticRelease, error)
    15â†’	GetSemanticReleaseSources(ctx context.Context, id string) ([]models.Release, error)
    16â†’	DeleteSemanticRelease(ctx context.Context, id string) error
    17â†’}
    18â†’
    19â†’// SemanticReleasesHandler implements HTTP handlers for the /semantic-releases resource.
    20â†’type SemanticReleasesHandler struct {
    21â†’	store SemanticReleasesStore
    22â†’}
