    24â†’// NewSemanticReleasesHandler returns a new SemanticReleasesHandler.
    25â†’func NewSemanticReleasesHandler(store SemanticReleasesStore) *SemanticReleasesHandler {
    26â†’	return &SemanticReleasesHandler{store: store}
    27â†’}
