	r := httptest.NewRequest(http.MethodGet, "/semantic-releases/sr-1/sources", nil)
	mux.ServeHTTP(w, r)

	if w.Code != http.StatusOK {
		t.Fatalf("expected status 200, got %d", w.Code)
	}

