     1â†’"use client";
     2â†’
     3â†’import useSWR from "swr";
     4â†’import Link from "next/link";
     5â†’import {
     6â†’  semanticReleases as srApi,
     7â†’  projects as projectsApi,
     8â†’  sources as sourcesApi,
     9â†’  contextSources,
    10â†’} from "@/lib/api/client";
    11â†’import { useRouter } from "next/navigation";
    12â†’import { StatusDot } from "@/components/ui/status-dot";
    13â†’import { VersionChip } from "@/components/ui/version-chip";
    14â†’import { SectionLabel } from "@/components/ui/section-label";
    15â†’import { ProviderBadge } from "@/components/ui/provider-badge";
    16â†’import { timeAgo } from "@/lib/format";
    17â†’import {
    18â†’  ArrowLeft,
    19â†’  Check,
    20â†’  ExternalLink,
    21â†’  Copy,
    22â†’  ShieldAlert,
    23â†’  BookOpen,
    24â†’} from "lucide-react";
    25â†’
    26â†’function getRiskColors(riskLevel?: string) {
    27â†’  switch (riskLevel?.toUpperCase()) {
    28â†’    case "CRITICAL":
    29â†’      return { border: "#dc2626", bg: "#fff1f2", text: "#991b1b" };
    30â†’    case "HIGH":
    31â†’      return { border: "#d97706", bg: "#fff8f0", text: "#92400e" };
    32â†’    case "MEDIUM":
    33â†’      return { border: "#ca8a04", bg: "#fefce8", text: "#854d0e" };
    34â†’    case "LOW":
    35â†’    default:
    36â†’      return { border: "#16a34a", bg: "#f0fdf4", text: "#166534" };
    37â†’  }
    38â†’}
    39â†’
    40â†’function safeHostname(url: string): string {
    41â†’  try {
    42â†’    return new URL(url).hostname.replace("www.", "");
    43â†’  } catch {
    44â†’    return url;
    45â†’  }
    46â†’}
    47â†’
    48â†’export function SemanticReleaseDetail({
    49â†’  projectId,
    50â†’  srId,
    51â†’}: {
    52â†’  projectId: string;
    53â†’  srId: string;
    54â†’}) {
    55â†’  const router = useRouter();
    56â†’  const { data, isLoading } = useSWR(`sr-${srId}`, () => srApi.get(srId));
    57â†’  const { data: projectData } = useSWR(`project-${projectId}`, () =>
    58â†’    projectsApi.get(projectId),
    59â†’  );
    60â†’  const { data: srSourcesData } = useSWR(`sr-sources-${srId}`, () =>
    61â†’    srApi.getSources(srId),
    62â†’  );
    63â†’  const { data: sourcesData } = useSWR(`project-sources-${projectId}`, () =>
    64â†’    sourcesApi.listByProject(projectId),
    65â†’  );
    66â†’  const { data: contextSourcesData } = useSWR(
    67â†’    `project-context-sources-${projectId}`,
    68â†’    () => contextSources.list(projectId),
    69â†’  );
    70â†’
    71â†’  if (isLoading) {
    72â†’    return (
    73â†’      <div className="flex justify-center py-20">
    74â†’        <div
    75â†’          className="text-[13px] text-[#9ca3af]"
    76â†’          style={{ fontFamily: "var(--font-dm-sans)" }}
    77â†’        >
    78â†’          Loading...
    79â†’        </div>
    80â†’      </div>
    81â†’    );
    82â†’  }
    83â†’
    84â†’  const sr = data?.data;
    85â†’  if (!sr) {
    86â†’    return (
    87â†’      <div className="flex justify-center py-20">
    88â†’        <div
    89â†’          className="text-[13px] text-[#9ca3af]"
    90â†’          style={{ fontFamily: "var(--font-dm-sans)" }}
    91â†’        >
    92â†’          Semantic release not found
    93â†’        </div>
    94â†’      </div>
    95â†’    );
    96â†’  }
    97â†’
    98â†’  const project = projectData?.data;
    99â†’  const releasesList = srSourcesData?.data ?? [];
   100â†’  const sourcesList = sourcesData?.data ?? [];
   101â†’  const sourcesById = Object.fromEntries(sourcesList.map((s) => [s.id, s]));
   102â†’  const contextSourcesList = contextSourcesData?.data ?? [];
   103â†’
   104â†’  const handleDelete = async () => {
   105â†’    if (!confirm("Delete this semantic release?")) return;
   106â†’    await srApi.delete(srId);
   107â†’    router.push("/semantic-releases");
   108â†’  };
   109â†’
   110â†’  const report = sr.report;
   111â†’  const riskLevel = report?.risk_level?.toUpperCase();
   112â†’  const hasRiskOrUrgency = riskLevel || report?.urgency;
   113â†’  const riskColors = getRiskColors(riskLevel);
   114â†’
   115â†’  const statusChecks = report?.status_checks ?? [];
   116â†’  const downloadLinks = report?.download_links ?? [];
   117â†’  const downloadCommands = report?.download_commands ?? [];
   118â†’  const hasAvailabilitySection =
   119â†’    statusChecks.length > 0 ||
   120â†’    downloadLinks.length > 0 ||
   121â†’    downloadCommands.length > 0;
   122â†’
   123â†’  return (
   124â†’    <div className="fade-in mx-auto max-w-[760px]">
   125â†’      {/* 1. Back link */}
   126â†’      <Link
   127â†’        href="/semantic-releases"
   128â†’        className="mb-6 inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
   129â†’        style={{
   130â†’          fontFamily: "var(--font-dm-sans)",
   131â†’          fontSize: "13px",
   132â†’          color: "#6b7280",
   133â†’        }}
   134â†’      >
   135â†’        <ArrowLeft size={14} />
   136â†’        Back to Semantic Releases
   137â†’      </Link>
   138â†’
   139â†’      {/* 2. Project byline */}
   140â†’      {project?.name && (
   141â†’        <p
   142â†’          className="mb-1 text-[13px] italic text-[#9ca3af]"
   143â†’          style={{ fontFamily: "var(--font-fraunces)" }}
   144â†’        >
   145â†’          {project.name}
   146â†’        </p>
   147â†’      )}
   148â†’
   149â†’      {/* 3. Version heading */}
   150â†’      <h1
   151â†’        className="text-[42px] font-bold tracking-tight text-[#111113] leading-[1.1]"
   152â†’        style={{ fontFamily: "var(--font-fraunces)" }}
   153â†’      >
   154â†’        {sr.version}
   155â†’      </h1>
   156â†’
   157â†’      {/* 4. Subject line */}
   158â†’      {report?.subject && (
   159â†’        <p
   160â†’          className="mt-2 text-[20px] leading-[1.4] text-[#374151]"
   161â†’          style={{ fontFamily: "var(--font-dm-sans)" }}
   162â†’        >
   163â†’          {report.subject}
   164â†’        </p>
   165â†’      )}
   166â†’
   167â†’      {/* 5. Meta line */}
   168â†’      <div
   169â†’        className="mt-3 flex items-center gap-2 text-[13px] text-[#6b7280]"
   170â†’        style={{ fontFamily: "var(--font-dm-sans)" }}
   171â†’      >
   172â†’        <StatusDot status={sr.status} />
   173â†’        <span className="flex-1">
   174â†’          {sr.status}
   175â†’          {sr.completed_at && ` \u00b7 generated ${timeAgo(sr.completed_at)}`}
   176â†’        </span>
   177â†’        <button
   178â†’          onClick={handleDelete}
   179â†’          className="rounded-md px-2.5 py-1 text-[12px] font-medium text-[#991b1b] transition-colors hover:bg-[#fef2f2]"
   180â†’          style={{ fontFamily: "var(--font-dm-sans)" }}
   181â†’        >
   182â†’          Delete
   183â†’        </button>
   184â†’      </div>
   185â†’
   186â†’      {/* 6. Divider */}
   187â†’      <hr
   188â†’        className="my-8 border-0"
   189â†’        style={{ borderTop: "1px solid #e8e8e5" }}
   190â†’      />
   191â†’
   192â†’      {/* 7. Error state */}
   193â†’      {sr.error && (
   194â†’        <div
   195â†’          className="mb-8 rounded-md px-4 py-3 text-[14px] text-[#991b1b]"
   196â†’          style={{
   197â†’            border: "1px solid #fca5a5",
   198â†’            backgroundColor: "#fef2f2",
   199â†’            fontFamily: "var(--font-dm-sans)",
   200â†’          }}
   201â†’        >
   202â†’          {sr.error}
   203â†’        </div>
   204â†’      )}
   205â†’
   206â†’      {report && (
   207â†’        <div className="space-y-10">
   208â†’          {/* 8. Risk & Urgency Banner */}
   209â†’          {hasRiskOrUrgency && (
   210â†’            <div
   211â†’              className="rounded-md px-4 py-4"
   212â†’              style={{
   213â†’                backgroundColor: riskColors.bg,
   214â†’                borderLeft: `3px solid ${riskColors.border}`,
   215â†’              }}
   216â†’            >
   217â†’              <div className="flex items-start gap-3">
   218â†’                <ShieldAlert
   219â†’                  className="h-5 w-5 mt-0.5 shrink-0"
   220â†’                  style={{ color: riskColors.border }}
   221â†’                />
   222â†’                <div className="flex-1">
   223â†’                  <div className="flex items-center gap-2 mb-1">
   224â†’                    {riskLevel && (
   225â†’                      <span
   226â†’                        className="rounded px-1.5 py-0.5 text-[11px] font-bold uppercase"
   227â†’                        style={{
   228â†’                          backgroundColor: riskColors.border,
   229â†’                          color: "#ffffff",
   230â†’                        }}
   231â†’                      >
   232â†’                        {riskLevel} RISK
   233â†’                      </span>
   234â†’                    )}
   235â†’                    {report.urgency && (
   236â†’                      <span
   237â†’                        className="text-[13px] font-medium"
   238â†’                        style={{ color: riskColors.text }}
   239â†’                      >
   240â†’                        {report.urgency} Urgency
   241â†’                      </span>
   242â†’                    )}
   243â†’                  </div>
   244â†’                  {report.risk_reason && (
   245â†’                    <p
   246â†’                      className="text-[14px] leading-[1.6]"
   247â†’                      style={{
   248â†’                        color: riskColors.text,
   249â†’                        fontFamily: "var(--font-dm-sans)",
   250â†’                      }}
   251â†’                    >
   252â†’                      {report.risk_reason}
   253â†’                    </p>
   254â†’                  )}
   255â†’                </div>
   256â†’              </div>
   257â†’            </div>
   258â†’          )}
   259â†’
   260â†’          {/* 9. Status Checks & Downloads */}
   261â†’          {hasAvailabilitySection && (
   262â†’            <section>
   263â†’              <SectionLabel className="mb-3">
   264â†’                Availability &amp; Downloads
   265â†’              </SectionLabel>
   266â†’
   267â†’              {/* Status checks as green pills */}
   268â†’              {statusChecks.length > 0 && (
   269â†’                <div className="flex flex-wrap gap-2 mb-4">
   270â†’                  {statusChecks.map((check) => (
   271â†’                    <span
   272â†’                      key={check}
   273â†’                      className="inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-[13px] font-medium"
   274â†’                      style={{
   275â†’                        backgroundColor: "#f0fdf4",
   276â†’                        color: "#166534",
   277â†’                        border: "1px solid #bbf7d0",
   278â†’                        fontFamily: "var(--font-dm-sans)",
   279â†’                      }}
   280â†’                    >
   281â†’                      <Check size={14} />
   282â†’                      {check}
   283â†’                    </span>
   284â†’                  ))}
   285â†’                </div>
   286â†’              )}
   287â†’
   288â†’              {/* Download links as pills */}
   289â†’              {downloadLinks.length > 0 && (
   290â†’                <div className="flex flex-wrap gap-2 mb-4">
   291â†’                  {downloadLinks.map((link) => (
   292â†’                    <a
   293â†’                      key={link}
   294â†’                      href={link}
   295â†’                      target="_blank"
   296â†’                      rel="noopener noreferrer"
   297â†’                      className="inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-[13px] font-medium transition-colors hover:opacity-80"
   298â†’                      style={{
   299â†’                        backgroundColor: "#f3f3f1",
   300â†’                        color: "#374151",
   301â†’                        border: "1px solid #e8e8e5",
   302â†’                        fontFamily: "var(--font-dm-sans)",
   303â†’                      }}
   304â†’                    >
   305â†’                      <ExternalLink size={12} />
   306â†’                      {safeHostname(link)}
   307â†’                    </a>
   308â†’                  ))}
   309â†’                </div>
   310â†’              )}
   311â†’
   312â†’              {/* Download commands as copiable code */}
   313â†’              {downloadCommands.length > 0 && (
   314â†’                <div className="space-y-2">
   315â†’                  {downloadCommands.map((cmd) => (
   316â†’                    <div
   317â†’                      key={cmd}
   318â†’                      className="group flex items-center gap-2 rounded-md px-3 py-2"
   319â†’                      style={{
   320â†’                        backgroundColor: "#fafaf9",
   321â†’                        border: "1px solid #e8e8e5",
   322â†’                      }}
   323â†’                    >
   324â†’                      <code
   325â†’                        className="flex-1 text-[13px] text-[#111113]"
   326â†’                        style={{ fontFamily: "'JetBrains Mono', monospace" }}
   327â†’                      >
   328â†’                        {cmd}
   329â†’                      </code>
   330â†’                      <button
   331â†’                        onClick={() => navigator.clipboard.writeText(cmd)}
   332â†’                        className="shrink-0 rounded p-1 text-[#9ca3af] opacity-0 transition-opacity group-hover:opacity-100 hover:text-[#374151]"
   333â†’                        title="Copy"
   334â†’                      >
   335â†’                        <Copy size={14} />
   336â†’                      </button>
   337â†’                    </div>
   338â†’                  ))}
   339â†’                </div>
   340â†’              )}
   341â†’            </section>
   342â†’          )}
   343â†’
   344â†’          {/* 10. Adoption */}
   345â†’          {report.adoption && (
   346â†’            <section>
   347â†’              <SectionLabel className="mb-2">Adoption</SectionLabel>
   348â†’              <div
   349â†’                className="rounded-md p-4"
   350â†’                style={{
   351â†’                  border: "1px solid #e8e8e5",
   352â†’                  backgroundColor: "#ffffff",
   353â†’                }}
   354â†’              >
   355â†’                <p
   356â†’                  className="text-[14px] leading-[1.6] text-[#111113]"
   357â†’                  style={{ fontFamily: "var(--font-dm-sans)" }}
   358â†’                >
   359â†’                  {report.adoption}
   360â†’                </p>
   361â†’              </div>
   362â†’            </section>
   363â†’          )}
   364â†’
   365â†’          {/* 11. Source Releases */}
   366â†’          {releasesList.length > 0 && (
   367â†’            <section>
   368â†’              <SectionLabel className="mb-4">Source Releases</SectionLabel>
   369â†’              <div
   370â†’                className="overflow-hidden rounded-md"
   371â†’                style={{ border: "1px solid #e8e8e5" }}
   372â†’              >
   373â†’                <table className="w-full text-left">
   374â†’                  <thead>
   375â†’                    <tr
   376â†’                      style={{
   377â†’                        backgroundColor: "#fafaf9",
   378â†’                        borderBottom: "1px solid #e8e8e5",
   379â†’                      }}
   380â†’                    >
   381â†’                      <th
   382â†’                        className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   383â†’                        style={{ fontFamily: "var(--font-dm-sans)" }}
   384â†’                      >
   385â†’                        Provider
   386â†’                      </th>
   387â†’                      <th
   388â†’                        className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   389â†’                        style={{ fontFamily: "var(--font-dm-sans)" }}
   390â†’                      >
   391â†’                        Repository
   392â†’                      </th>
   393â†’                      <th
   394â†’                        className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   395â†’                        style={{ fontFamily: "var(--font-dm-sans)" }}
   396â†’                      >
   397â†’                        Version
   398â†’                      </th>
   399â†’                      <th
   400â†’                        className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   401â†’                        style={{ fontFamily: "var(--font-dm-sans)" }}
   402â†’                      >
   403â†’                        Date
   404â†’                      </th>
   405â†’                    </tr>
   406â†’                  </thead>
   407â†’                  <tbody>
   408â†’                    {releasesList.map((rel) => {
   409â†’                      const source = sourcesById[rel.source_id];
   410â†’                      const versionUrl =
   411â†’                        source?.provider === "github"
   412â†’                          ? `https://github.com/${source.repository}/releases/tag/${rel.version}`
   413â†’                          : source?.provider === "dockerhub"
   414â†’                            ? `https://hub.docker.com/r/${source.repository}/tags?name=${rel.version}`
   415â†’                            : null;
   416â†’
   417â†’                      return (
   418â†’                        <tr
   419â†’                          key={rel.id}
   420â†’                          style={{ borderBottom: "1px solid #e8e8e5" }}
   421â†’                          className="last:border-b-0"
   422â†’                        >
   423â†’                          <td className="px-4 py-3">
   424â†’                            {source ? (
   425â†’                              <ProviderBadge provider={source.provider} />
   426â†’                            ) : (
   427â†’                              <span className="text-[12px] text-[#9ca3af]">
   428â†’                                {"\u2014"}
   429â†’                              </span>
   430â†’                            )}
   431â†’                          </td>
   432â†’                          <td className="px-4 py-3">
   433â†’                            <span
   434â†’                              className="text-[13px] text-[#374151]"
   435â†’                              style={{
   436â†’                                fontFamily: "'JetBrains Mono', monospace",
   437â†’                              }}
   438â†’                            >
   439â†’                              {source?.repository ?? "\u2014"}
   440â†’                            </span>
   441â†’                          </td>
   442â†’                          <td className="px-4 py-3">
   443â†’                            {versionUrl ? (
   444â†’                              <a
   445â†’                                href={versionUrl}
   446â†’                                target="_blank"
   447â†’                                rel="noopener noreferrer"
   448â†’                                className="inline-flex items-center gap-1 hover:opacity-70 transition-opacity"
   449â†’                              >
   450â†’                                <VersionChip version={rel.version} />
   451â†’                                <ExternalLink
   452â†’                                  size={11}
   453â†’                                  className="text-[#9ca3af]"
   454â†’                                />
   455â†’                              </a>
   456â†’                            ) : (
   457â†’                              <VersionChip version={rel.version} />
   458â†’                            )}
   459â†’                          </td>
   460â†’                          <td className="px-4 py-3">
   461â†’                            <span
   462â†’                              className="text-[13px] text-[#6b7280]"
   463â†’                              style={{ fontFamily: "var(--font-dm-sans)" }}
   464â†’                            >
   465â†’                              {timeAgo(rel.released_at ?? rel.created_at)}
   466â†’                            </span>
   467â†’                          </td>
   468â†’                        </tr>
   469â†’                      );
   470â†’                    })}
   471â†’                  </tbody>
   472â†’                </table>
   473â†’              </div>
   474â†’            </section>
   475â†’          )}
   476â†’
   477â†’          {/* 12. Context Sources */}
   478â†’          {contextSourcesList.length > 0 && (
   479â†’            <section>
   480â†’              <SectionLabel className="mb-3">Context Sources</SectionLabel>
   481â†’              <div className="space-y-2">
   482â†’                {contextSourcesList.map((cs) => {
   483â†’                  const url = cs.config?.url as string | undefined;
   484â†’                  return (
   485â†’                    <div
   486â†’                      key={cs.id}
   487â†’                      className="flex items-center gap-3 rounded-md px-4 py-3"
   488â†’                      style={{
   489â†’                        border: "1px solid #e8e8e5",
   490â†’                        backgroundColor: "#ffffff",
   491â†’                      }}
   492â†’                    >
   493â†’                      <BookOpen
   494â†’                        size={16}
   495â†’                        className="shrink-0 text-[#9ca3af]"
   496â†’                      />
   497â†’                      <div className="flex-1 min-w-0">
   498â†’                        <span
   499â†’                          className="text-[14px] font-medium text-[#111113]"
   500â†’                          style={{ fontFamily: "var(--font-dm-sans)" }}
   501â†’                        >
   502â†’                          {cs.name}
   503â†’                        </span>
   504â†’                        <span
   505â†’                          className="ml-2 rounded px-1.5 py-0.5 text-[11px] font-medium uppercase text-[#6b7280]"
   506â†’                          style={{ backgroundColor: "#f3f3f1" }}
   507â†’                        >
   508â†’                          {cs.type}
   509â†’                        </span>
   510â†’                      </div>
   511â†’                      {url && (
   512â†’                        <a
   513â†’                          href={url}
   514â†’                          target="_blank"
   515â†’                          rel="noopener noreferrer"
   516â†’                          className="shrink-0 text-[#9ca3af] hover:text-[#374151] transition-colors"
   517â†’                        >
   518â†’                          <ExternalLink size={14} />
   519â†’                        </a>
   520â†’                      )}
   521â†’                    </div>
   522â†’                  );
   523â†’                })}
   524â†’              </div>
