    52â†’export function ReleaseDetail({ id }: { id: string }) {
    53â†’  /* Fetch release */
    54â†’  const { data: releaseData, isLoading } = useSWR(`release-${id}`, () =>
    55â†’    releasesApi.get(id)
    56â†’  );
    57â†’
    58â†’  const release = releaseData?.data;
    59â†’
    60â†’  /* Fetch source info once we have the release */
    61â†’  const { data: sourceData } = useSWR(
    62â†’    release ? `source-${release.source_id}` : null,
    63â†’    () => (release ? sourcesApi.get(release.source_id) : null)
    64â†’  );
    65â†’  const source: Source | undefined = sourceData?.data;
    66â†’
    67â†’  /* Fetch project info once we have the source */
