    76â†’    source ? `sr-for-release-${id}` : null,
    77â†’    async () => {
    78â†’      if (!source) return [];
    79â†’      const res = await srApi.list(source.project_id, 1).catch(() => null);
    80â†’      if (!res?.data) return [];
    81â†’      /* Filter semantic releases whose version matches this release version */
    82â†’      return res.data.filter((sr: SemanticRelease) => sr.version === release?.version);
    83â†’    }
