   121â†’  return (
   122â†’    <div className="space-y-8">
   123â†’      {/* Back link */}
   124â†’      <Link
   125â†’        href="/releases"
   126â†’        className="inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
   127â†’        style={{
   128â†’          fontFamily: "var(--font-dm-sans)",
   129â†’          fontSize: "13px",
   130â†’          color: "#6b7280",
   131â†’        }}
   132â†’      >
