    49â†’	feedURL := fmt.Sprintf("%s/%s/releases.atom", s.baseURL, s.repository)
    50â†’
    51â†’	req, err := http.NewRequestWithContext(ctx, http.MethodGet, feedURL, nil)
    52â†’	if err != nil {
    53â†’		return nil, fmt.Errorf("create request: %w", err)
    54â†’	}
    55â†’
    56â†’	resp, err := s.client.Do(req)
    57â†’	if err != nil {
    58â†’		return nil, fmt.Errorf("fetch atom feed: %w", err)
    59â†’	}
    60â†’	defer resp.Body.Close()
    61â†’
    62â†’	if resp.StatusCode != http.StatusOK {
    63â†’		return nil, fmt.Errorf("unexpected status: %d", resp.StatusCode)
