    73â†’		version := extractVersion(entry.ID)
    74â†’		if version == "" {
    75â†’			continue
    76â†’		}
    77â†’		ts, _ := time.Parse(time.RFC3339, entry.Updated)
    78â†’		results = append(results, IngestionResult{
    79â†’			Repository: s.repository,
