    25â†’// IngestRelease inserts a release and enqueues a notify job in a single transaction.
    26â†’// Returns an error on unique constraint violation (caller treats as idempotent skip).
    27â†’func (s *PgStore) IngestRelease(ctx context.Context, sourceID string, result *IngestionResult) error {
    28â†’	tx, err := s.pool.Begin(ctx)
    29â†’	if err != nil {
    30â†’		return fmt.Errorf("begin tx: %w", err)
    31â†’	}
    32â†’	defer tx.Rollback(ctx)
    33â†’
    34â†’	// Build raw_data from Metadata + Changelog so nothing is lost.
    35â†’	raw := make(map[string]string)
    36â†’	for k, v := range result.Metadata {
    37â†’		raw[k] = v
    38â†’	}
    39â†’	if result.Changelog != "" {
    40â†’		raw["changelog"] = result.Changelog
    41â†’	}
    42â†’	rawData, err := json.Marshal(raw)
    43â†’	if err != nil {
    44â†’		return fmt.Errorf("marshal raw_data: %w", err)
    45â†’	}
    46â†’
    47â†’	releaseID := uuid.New().String()
    48â†’	_, err = tx.Exec(ctx,
    49â†’		`INSERT INTO releases (id, source_id, version, raw_data, released_at) VALUES ($1, $2, $3, $4, $5)`,
    50â†’		releaseID, sourceID, result.RawVersion, rawData, result.Timestamp,
    51â†’	)
    52â†’	if err != nil {
    53â†’		return fmt.Errorf("insert release: %w", err)
    54â†’	}
    55â†’
    56â†’	_, err = s.river.InsertTx(ctx, tx, queue.NotifyJobArgs{
    57â†’		ReleaseID: releaseID,
    58â†’		SourceID:  sourceID,
    59â†’	}, nil)
    60â†’	if err != nil {
    61â†’		return fmt.Errorf("enqueue job: %w", err)
    62â†’	}
    63â†’
    64â†’	if err := tx.Commit(ctx); err != nil {
    65â†’		return fmt.Errorf("commit: %w", err)
    66â†’	}
    67â†’	return nil
    68â†’}
