    92â†’          Semantic release not found
    93â†’        </div>
    94â†’      </div>
    95â†’    );
    96â†’  }
    97â†’
    98â†’  const project = projectData?.data;
    99â†’  const releasesList = srSourcesData?.data ?? [];
   100â†’  const sourcesList = sourcesData?.data ?? [];
   101â†’  const sourcesById = Object.fromEntries(sourcesList.map((s) => [s.id, s]));
   102â†’  const contextSourcesList = contextSourcesData?.data ?? [];
   103â†’
   104â†’  const handleDelete = async () => {
   105â†’    if (!confirm("Delete this semantic release?")) return;
   106â†’    try {
   107â†’      await srApi.delete(srId);
   108â†’      router.push("/semantic-releases");
   109â†’    } catch {
   110â†’      alert("Failed to delete semantic release.");
   111â†’    }
   112â†’  };
   113â†’
   114â†’  const report = sr.report;
   115â†’  const riskLevel = report?.risk_level?.toUpperCase();
   116â†’  const hasRiskOrUrgency = riskLevel || report?.urgency;
   117â†’  const riskColors = getRiskColors(riskLevel);
   118â†’
   119â†’  const statusChecks = report?.status_checks ?? [];
   120â†’  const downloadLinks = report?.download_links ?? [];
   121â†’  const downloadCommands = report?.download_commands ?? [];
   122â†’  const hasAvailabilitySection =
   123â†’    statusChecks.length > 0 ||
   124â†’    downloadLinks.length > 0 ||
   125â†’    downloadCommands.length > 0;
   126â†’
   127â†’  return (
   128â†’    <div className="fade-in mx-auto max-w-[760px]">
   129â†’      {/* 1. Back link */}
   130â†’      <Link
   131â†’        href="/semantic-releases"
   132â†’        className="mb-6 inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
   133â†’        style={{
   134â†’          fontFamily: "var(--font-dm-sans)",
   135â†’          fontSize: "13px",
   136â†’          color: "#6b7280",
   137â†’        }}
   138â†’      >
   139â†’        <ArrowLeft size={14} />
   140â†’        Back to Semantic Releases
   141â†’      </Link>
   142â†’
   143â†’      {/* 2. Project byline */}
   144â†’      {project?.name && (
   145â†’        <p
   146â†’          className="mb-1 text-[13px] italic text-[#9ca3af]"
   147â†’          style={{ fontFamily: "var(--font-fraunces)" }}
   148â†’        >
   149â†’          {project.name}
   150â†’        </p>
   151â†’      )}
   152â†’
   153â†’      {/* 3. Version heading */}
   154â†’      <h1
   155â†’        className="text-[42px] font-bold tracking-tight text-[#111113] leading-[1.1]"
   156â†’        style={{ fontFamily: "var(--font-fraunces)" }}
   157â†’      >
   158â†’        {sr.version}
   159â†’      </h1>
   160â†’
   161â†’      {/* 4. Subject line */}
   162â†’      {report?.subject && (
   163â†’        <p
   164â†’          className="mt-2 text-[20px] leading-[1.4] text-[#374151]"
   165â†’          style={{ fontFamily: "var(--font-dm-sans)" }}
   166â†’        >
   167â†’          {report.subject}
   168â†’        </p>
   169â†’      )}
   170â†’
   171â†’      {/* 5. Meta line */}
   172â†’      <div
   173â†’        className="mt-3 flex items-center gap-2 text-[13px] text-[#6b7280]"
   174â†’        style={{ fontFamily: "var(--font-dm-sans)" }}
   175â†’      >
   176â†’        <StatusDot status={sr.status} />
   177â†’        <span className="flex-1">
   178â†’          {sr.status}
   179â†’          {sr.completed_at && ` \u00b7 generated ${timeAgo(sr.completed_at)}`}
   180â†’        </span>
   181â†’        <button
   182â†’          onClick={handleDelete}
   183â†’          className="rounded-md px-2.5 py-1 text-[12px] font-medium text-[#991b1b] transition-colors hover:bg-[#fef2f2]"
   184â†’          style={{ fontFamily: "var(--font-dm-sans)" }}
   185â†’        >
   186â†’          Delete
   187â†’        </button>
   188â†’      </div>
   189â†’
   190â†’      {/* 6. Divider */}
   191â†’      <hr
   192â†’        className="my-8 border-0"
   193â†’        style={{ borderTop: "1px solid #e8e8e5" }}
   194â†’      />
   195â†’
   196â†’      {/* 7. Error state */}
   197â†’      {sr.error && (
   198â†’        <div
   199â†’          className="mb-8 rounded-md px-4 py-3 text-[14px] text-[#991b1b]"
   200â†’          style={{
   201â†’            border: "1px solid #fca5a5",
   202â†’            backgroundColor: "#fef2f2",
   203â†’            fontFamily: "var(--font-dm-sans)",
   204â†’          }}
   205â†’        >
   206â†’          {sr.error}
   207â†’        </div>
   208â†’      )}
   209â†’
   210â†’      {report && (
   211â†’        <div className="space-y-10">
   212â†’          {/* 8. Risk & Urgency Banner */}
   213â†’          {hasRiskOrUrgency && (
   214â†’            <div
   215â†’              className="rounded-md px-4 py-4"
   216â†’              style={{
   217â†’                backgroundColor: riskColors.bg,
   218â†’                borderLeft: `3px solid ${riskColors.border}`,
   219â†’              }}
   220â†’            >
   221â†’              <div className="flex items-start gap-3">
   222â†’                <ShieldAlert
   223â†’                  className="h-5 w-5 mt-0.5 shrink-0"
   224â†’                  style={{ color: riskColors.border }}
   225â†’                />
   226â†’                <div className="flex-1">
   227â†’                  <div className="flex items-center gap-2 mb-1">
   228â†’                    {riskLevel && (
   229â†’                      <span
   230â†’                        className="rounded px-1.5 py-0.5 text-[11px] font-bold uppercase"
   231â†’                        style={{
   232â†’                          backgroundColor: riskColors.border,
   233â†’                          color: "#ffffff",
   234â†’                        }}
   235â†’                      >
   236â†’                        {riskLevel} RISK
   237â†’                      </span>
   238â†’                    )}
   239â†’                    {report.urgency && (
   240â†’                      <span
   241â†’                        className="text-[13px] font-medium"
   242â†’                        style={{ color: riskColors.text }}
   243â†’                      >
   244â†’                        {report.urgency} Urgency
   245â†’                      </span>
   246â†’                    )}
   247â†’                  </div>
   248â†’                  {report.risk_reason && (
   249â†’                    <p
   250â†’                      className="text-[14px] leading-[1.6]"
   251â†’                      style={{
   252â†’                        color: riskColors.text,
   253â†’                        fontFamily: "var(--font-dm-sans)",
   254â†’                      }}
   255â†’                    >
   256â†’                      {report.risk_reason}
   257â†’                    </p>
   258â†’                  )}
   259â†’                </div>
   260â†’              </div>
   261â†’            </div>
   262â†’          )}
   263â†’
   264â†’          {/* 9. Status Checks & Downloads */}
   265â†’          {hasAvailabilitySection && (
   266â†’            <section>
   267â†’              <SectionLabel className="mb-3">
   268â†’                Availability & Downloads
   269â†’              </SectionLabel>
   270â†’
   271â†’              {/* Status checks as green pills */}
   272â†’              {statusChecks.length > 0 && (
   273â†’                <div className="flex flex-wrap gap-2 mb-4">
   274â†’                  {statusChecks.map((check) => (
   275â†’                    <span
   276â†’                      key={check}
   277â†’                      className="inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-[13px] font-medium"
   278â†’                      style={{
   279â†’                        backgroundColor: "#f0fdf4",
   280â†’                        color: "#166534",
   281â†’                        border: "1px solid #bbf7d0",
   282â†’                        fontFamily: "var(--font-dm-sans)",
   283â†’                      }}
   284â†’                    >
   285â†’                      <Check size={14} />
   286â†’                      {check}
   287â†’                    </span>
   288â†’                  ))}
   289â†’                </div>
   290â†’              )}
   291â†’
   292â†’              {/* Download links as pills */}
   293â†’              {downloadLinks.length > 0 && (
   294â†’                <div className="flex flex-wrap gap-2 mb-4">
   295â†’                  {downloadLinks.map((link) => (
