   301â†’                      className="inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-[13px] font-medium transition-colors hover:opacity-80"
   302â†’                      style={{
   303â†’                        backgroundColor: "#f3f3f1",
   304â†’                        color: "#374151",
   305â†’                        border: "1px solid #e8e8e5",
   306â†’                        fontFamily: "var(--font-dm-sans)",
   307â†’                      }}
   308â†’                    >
   309â†’                      <ExternalLink size={12} />
   310â†’                      {safeHostname(link)}
   311â†’                    </a>
   312â†’                  ))}
   313â†’                </div>
