   323â†’                      style={{
   324â†’                        backgroundColor: "#fafaf9",
   325â†’                        border: "1px solid #e8e8e5",
   326â†’                      }}
   327â†’                    >
   328â†’                      <code
   329â†’                        className="flex-1 text-[13px] text-[#111113]"
   330â†’                        style={{ fontFamily: "'JetBrains Mono', monospace" }}
