   333â†’                      </code>
   334â†’                      <button
   335â†’                        onClick={() => navigator.clipboard.writeText(cmd)}
   336â†’                        className="shrink-0 rounded p-1 text-[#9ca3af] opacity-0 transition-opacity group-hover:opacity-100 hover:text-[#374151]"
   337â†’                        title="Copy"
   338â†’                      >
   339â†’                        <Copy size={14} />
   340â†’                      </button>
   341â†’                    </div>
   342â†’                  ))}
   343â†’                </div>
   344â†’              )}
   345â†’            </section>
   346â†’          )}
   347â†’
   348â†’          {/* 10. Adoption */}
   349â†’          {report.adoption && (
   350â†’            <section>
   351â†’              <SectionLabel className="mb-2">Adoption</SectionLabel>
   352â†’              <div
   353â†’                className="rounded-md p-4"
   354â†’                style={{
   355â†’                  border: "1px solid #e8e8e5",
   356â†’                  backgroundColor: "#ffffff",
   357â†’                }}
   358â†’              >
   359â†’                <p
   360â†’                  className="text-[14px] leading-[1.6] text-[#111113]"
   361â†’                  style={{ fontFamily: "var(--font-dm-sans)" }}
   362â†’                >
   363â†’                  {report.adoption}
   364â†’                </p>
   365â†’              </div>
   366â†’            </section>
   367â†’          )}
   368â†’
   369â†’          {/* 11. Source Releases */}
   370â†’          {releasesList.length > 0 && (
