   392â†’                        className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   393â†’                        style={{ fontFamily: "var(--font-dm-sans)" }}
   394â†’                      >
   395â†’                        Repository
   396â†’                      </th>
   397â†’                      <th
   398â†’                        className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   399â†’                        style={{ fontFamily: "var(--font-dm-sans)" }}
   400â†’                      >
   401â†’                        Version
   402â†’                      </th>
   403â†’                      <th
   404â†’                        className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   405â†’                        style={{ fontFamily: "var(--font-dm-sans)" }}
   406â†’                      >
   407â†’                        Date
   408â†’                      </th>
   409â†’                    </tr>
   410â†’                  </thead>
   411â†’                  <tbody>
   412â†’                    {releasesList.map((rel) => {
   413â†’                      const source = sourcesById[rel.source_id];
   414â†’                      const versionUrl =
   415â†’                        source?.provider === "github"
   416â†’                          ? `https://github.com/${source.repository}/releases/tag/${rel.version}`
   417â†’                          : source?.provider === "dockerhub"
   418â†’                            ? `https://hub.docker.com/r/${source.repository}/tags?name=${encodeURIComponent(rel.version)}`
   419â†’                            : null;
   420â†’
   421â†’                      return (
