   423â†’                          key={rel.id}
   424â†’                          className="border-b border-[#e8e8e5] last:border-b-0"
   425â†’                        >
   426â†’                          <td className="px-4 py-3">
   427â†’                            {source ? (
   428â†’                              <ProviderBadge provider={source.provider} />
   429â†’                            ) : (
   430â†’                              <span className="text-[12px] text-[#9ca3af]">
   431â†’                                {"\u2014"}
   432â†’                              </span>
   433â†’                            )}
   434â†’                          </td>
   435â†’                          <td className="px-4 py-3">
   436â†’                            <span
   437â†’                              className="text-[13px] text-[#374151]"
   438â†’                              style={{
   439â†’                                fontFamily: "'JetBrains Mono', monospace",
   440â†’                              }}
   441â†’                            >
   442â†’                              {source?.repository ?? "\u2014"}
   443â†’                            </span>
   444â†’                          </td>
   445â†’                          <td className="px-4 py-3">
   446â†’                            {versionUrl ? (
   447â†’                              <a
   448â†’                                href={versionUrl}
   449â†’                                target="_blank"
   450â†’                                rel="noopener noreferrer"
   451â†’                                className="inline-flex items-center gap-1 hover:opacity-70 transition-opacity"
   452â†’                              >
   453â†’                                <VersionChip version={rel.version} />
   454â†’                                <ExternalLink
   455â†’                                  size={11}
   456â†’                                  className="text-[#9ca3af]"
   457â†’                                />
   458â†’                              </a>
   459â†’                            ) : (
   460â†’                              <VersionChip version={rel.version} />
   461â†’                            )}
   462â†’                          </td>
   463â†’                          <td className="px-4 py-3">
   464â†’                            <span
   465â†’                              className="text-[13px] text-[#6b7280]"
   466â†’                              style={{ fontFamily: "var(--font-dm-sans)" }}
   467â†’                            >
   468â†’                              {timeAgo(rel.released_at ?? rel.created_at)}
   469â†’                            </span>
   470â†’                          </td>
   471â†’                        </tr>
   472â†’                      );
   473â†’                    })}
   474â†’                  </tbody>
   475â†’                </table>
   476â†’              </div>
   477â†’            </section>
   478â†’          )}
   479â†’
   480â†’          {/* 12. Context Sources */}
   481â†’          {contextSourcesList.length > 0 && (
   482â†’            <section>
   483â†’              <SectionLabel className="mb-3">Context Sources</SectionLabel>
   484â†’              <div className="space-y-2">
   485â†’                {contextSourcesList.map((cs) => {
   486â†’                  const url = cs.config?.url as string | undefined;
   487â†’                  return (
   488â†’                    <div
