   499â†’                      />
   500â†’                      <div className="flex-1 min-w-0">
   501â†’                        <span
   502â†’                          className="text-[14px] font-medium text-[#111113]"
   503â†’                          style={{ fontFamily: "var(--font-dm-sans)" }}
