   535â†’              <p
   536â†’                className="text-[16px] leading-[1.7] text-[#111113]"
   537â†’                style={{ fontFamily: "var(--font-dm-sans)" }}
   538â†’              >
   539â†’                {report.changelog_summary}
   540â†’              </p>
   541â†’            </section>
   542â†’          )}
   543â†’
   544â†’          {/* 14. Recommendation pull-quote */}
   545â†’          {report.recommendation && (
