   135â†’func (m *openaiModel) doRequest(ctx context.Context, req *model.LLMRequest) (*model.LLMResponse, error) {
   136â†’	msgs := convertContents(req)
   137â†’	tools := convertTools(req)
   138â†’
   139â†’	chatReq := chatRequest{
   140â†’		Model:    m.name,
   141â†’		Messages: msgs,
   142â†’		Tools:    tools,
   143â†’		Stream:   false,
   144â†’	}
   145â†’
   146â†’	if req.Config != nil {
   147â†’		chatReq.Temperature = req.Config.Temperature
   148â†’		chatReq.TopP = req.Config.TopP
   149â†’		if req.Config.MaxOutputTokens > 0 {
   150â†’			chatReq.MaxTokens = req.Config.MaxOutputTokens
   151â†’		}
   152â†’		if len(req.Config.StopSequences) > 0 {
   153â†’			chatReq.Stop = req.Config.StopSequences
   154â†’		}
   155â†’	}
   156â†’
   157â†’	body, err := json.Marshal(chatReq)
   158â†’	if err != nil {
   159â†’		return nil, fmt.Errorf("openai: marshal request: %w", err)
   160â†’	}
   161â†’
   162â†’	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, m.baseURL+"/chat/completions", bytes.NewReader(body))
   163â†’	if err != nil {
   164â†’		return nil, fmt.Errorf("openai: create http request: %w", err)
   165â†’	}
   166â†’	httpReq.Header.Set("Content-Type", "application/json")
   167â†’	httpReq.Header.Set("Authorization", "Bearer "+m.apiKey)
   168â†’
   169â†’	httpResp, err := m.client.Do(httpReq)
   170â†’	if err != nil {
   171â†’		return nil, fmt.Errorf("openai: http request: %w", err)
   172â†’	}
   173â†’	defer httpResp.Body.Close()
   174â†’
   175â†’	respBody, err := io.ReadAll(httpResp.Body)
   176â†’	if err != nil {
   177â†’		return nil, fmt.Errorf("openai: read response: %w", err)
   178â†’	}
   179â†’
   180â†’	if httpResp.StatusCode != http.StatusOK {
   181â†’		return nil, fmt.Errorf("openai: API returned status %d: %s", httpResp.StatusCode, string(respBody))
   182â†’	}
   183â†’
   184â†’	var chatResp chatResponse
   185â†’	if err := json.Unmarshal(respBody, &chatResp); err != nil {
   186â†’		return nil, fmt.Errorf("openai: unmarshal response: %w", err)
   187â†’	}
   188â†’
   189â†’	if chatResp.Error != nil {
